    results.push(test_leader_completeness());
    results.push(test_follower_catchup());
    results.push(test_stale_leader_detection());
    results.push(test_term_monotonic_increase());
    results.push(test_apply_committed_entries());
    results.push(test_network_partition_recovery());
    results.push(test_leader_crash_reelection());
    results.push(test_5node_cluster());

    // Print results
    let i = 0;
    let passed = 0;
    while (i < results.len()) {
        print_test_result(results[i]);
        if (results[i].passed) {
            passed = passed + 1;
        };
        i = i + 1;
    };

    print("");
    print("===============================================");
    print("Results: " + passed + " / " + results.len() + " tests passed");
    print("===============================================");
}

// Main entry point
run_all_tests();

