    let v1 = get(store, "user:1");
    let v2 = get(store, "user:2");
    let v3 = get(store, "user:3");

    let all_retrieved = (v1 == "alice") && (v2 == "bob") && (v3 == "charlie");

    return assert_true(all_retrieved, "test_cross_shard_query");
}

// ============================================================================
// Test 12: Range Scan
// ============================================================================

fn test_range_scan() -> TestResult {
    let store = new_sharded_kv_store(3);
    store = add_node_to_store(store, 0);
    store = add_node_to_store(store, 1);

    // Add sequential keys
    let i = 0;
    while (i < 10) {
        let key = "item:" + i;
        store = put(store, key, "value");
        i = i + 1;
    };

    // Verify all keys are stored
    let found = 0;
    let j = 0;
    while (j < 10) {
        let key = "item:" + j;
        let value = get(store, key);
        if (value == "value") {
            found = found + 1;
        };
        j = j + 1;
    };

    return assert_equal_u32(found, 10, "test_range_scan");
}

// ============================================================================
// Test 13: Shard Split (Conceptual)
// ============================================================================

fn test_shard_split() -> TestResult {
    let store = new_sharded_kv_store(3);
    store = add_node_to_store(store, 0);
    store = add_node_to_store(store, 1);

    // Add many keys
    let i = 0;
    while (i < 100) {
        let key = "key:" + i;
        store = put(store, key, "value");
        i = i + 1;
    };

    // Split: add new node (causes redistribution)
    store = add_node_to_store(store, 2);

    // Data should still be accessible
    let v = get(store, "key:50");

    return assert_equal(v, "value", "test_shard_split");
}

// ============================================================================
// Test 14: Shard Merge (Conceptual)
// ============================================================================

fn test_shard_merge() -> TestResult {
    let store = new_sharded_kv_store(3);
    store = add_node_to_store(store, 0);
    store = add_node_to_store(store, 1);
    store = add_node_to_store(store, 2);

    // Add keys
    let i = 0;
    while (i < 50) {
        let key = "key:" + i;
        store = put(store, key, "value");
        i = i + 1;
    };

    // Merge: remove node (consolidates shards)
    store = remove_node_from_store(store, 2);

    // Data should still be accessible
    let v = get(store, "key:25");

    return assert_equal(v, "value", "test_shard_merge");
}

// ============================================================================
// Test 15: Load Distribution Balance
// ============================================================================

fn test_load_distribution() -> TestResult {
    let store = new_sharded_kv_store(3);
    store = add_node_to_store(store, 0);
    store = add_node_to_store(store, 1);
    store = add_node_to_store(store, 2);

    // Add many keys
    let i = 0;
    while (i < 300) {
        let key = "key:" + i;
        store = put(store, key, "value");
        i = i + 1;
    };

    // Check balance
    let balanced = check_balance(store);

    return assert_true(balanced, "test_load_distribution");
}

// ============================================================================
// Test Runner
// ============================================================================

fn run_all_tests() {
    print("===============================================");
    print("Consistent Hashing & Sharding Tests - Week 2");
    print("===============================================");

    let results = [];

    // Run all 15 tests
    results.push(test_hash_ring_creation());
    results.push(test_consistent_mapping());
    results.push(test_add_node_minimal_movement());
    results.push(test_remove_node_redistribution());
    results.push(test_virtual_node_balance());
    results.push(test_shard_key_lookup());
    results.push(test_sharded_put_get());
    results.push(test_replication_factor());
    results.push(test_node_failure_redistribution());
    results.push(test_hotspot_detection());
    results.push(test_cross_shard_query());
    results.push(test_range_scan());
    results.push(test_shard_split());
    results.push(test_shard_merge());
    results.push(test_load_distribution());

    // Print results
    let i = 0;
    let passed = 0;
    while (i < results.len()) {
        print_test_result(results[i]);
        if (results[i].passed) {
            passed = passed + 1;
        };
        i = i + 1;
    };

    print("");
    print("===============================================");
    print("Results: " + passed + " / " + results.len() + " tests passed");
    print("===============================================");
}

// Main entry point
run_all_tests();

