fn calculate_fragmentation(tracker: &MemoryAllocationTracker) -> f64 {
    // Fragmentation = (Peak - Current) / Peak × 100%
    if (tracker.peak_memory == 0) {
        return 0.0;
    };

    let leaked = tracker.peak_memory - tracker.current_memory;
    (leaked as f64) / (tracker.peak_memory as f64) * 100.0
}

// Test 13: Sequential allocation/deallocation pattern
fn test_sequential_pattern() -> TestResult {
    let tracker = create_tracker();

    // Pattern: Allocate 10 objects, deallocate all, repeat 5 times
    let cycle = 0;
    while (cycle < 5) {
        let i = 0;
        while (i < 10) {
            track_allocation(tracker, 32);
            i = i + 1;
        };

        let j = 0;
        while (j < 10) {
            track_deallocation(tracker, 32);
            j = j + 1;
        };

        cycle = cycle + 1;
    };

    let frag = calculate_fragmentation(tracker);

    // Sequential pattern should have 0% fragmentation
    let passed = frag <= 5.0;  // Allow 5% margin

    TestResult {
        name: "test_sequential_pattern",
        passed: passed,
        memory_leaked: false,
        circular_ref_found: false,
        fragmentation_ratio: frag,
        error_message: if (passed) "" else "Sequential pattern fragmentation too high",
