}

// Test 15: Highly fragmented pattern
fn test_fragmented_pattern() -> TestResult {
    let tracker = create_tracker();

    // Pattern: Allocate 100 small objects, deallocate odd indices
    // Result: 50 isolated blocks with gaps

    let i = 0;
    while (i < 100) {
        track_allocation(tracker, 8);
        if (i % 2 == 1) {
            track_deallocation(tracker, 8);
        };
