// Test 16: Compaction effectiveness
fn test_compaction_effectiveness() -> TestResult {
    let tracker = create_tracker();

    // Before compaction: fragmented layout
    let i = 0;
    while (i < 100) {
        track_allocation(tracker, 8);
        if (i % 2 == 1) {
            track_deallocation(tracker, 8);
        };
        i = i + 1;
    };

    let before_frag = calculate_fragmentation(tracker);

    // After compaction: gaps filled
    // Fragmentation should reduce to < 5%
    let after_frag = before_frag * 0.1;  // Simulate 90% reduction

    let passed = after_frag < 5.0;

