// ============================================================================
// Part 1: Test Framework (200 lines)
// ============================================================================

struct MemoryStats {
    allocated: u64,
    freed: u64,
    peak: u64,
    fragmentation: f64,
    circular_refs_detected: u32,
    circular_refs_resolved: u32,
}

struct TestResult {
    name: string,
    passed: bool,
    memory_leaked: bool,
    circular_ref_found: bool,
    fragmentation_ratio: f64,
    error_message: string,
}

struct MemoryAllocationTracker {
    allocations: vector,  // array of (ptr, size, timestamp)
    deallocations: vector,
    current_memory: u64,
    peak_memory: u64,
    total_allocated: u64,
    total_freed: u64,
}

fn create_tracker() -> MemoryAllocationTracker {
    MemoryAllocationTracker {
        allocations: [],
        deallocations: [],
        current_memory: 0,
        peak_memory: 0,
        total_allocated: 0,
        total_freed: 0,
    }
}

fn track_allocation(tracker: &MemoryAllocationTracker, size: u64) {
    tracker.allocations.push(size);
    tracker.current_memory = tracker.current_memory + size;
    tracker.total_allocated = tracker.total_allocated + size;

    if (tracker.current_memory > tracker.peak_memory) {
        tracker.peak_memory = tracker.current_memory;
    };
}

fn track_deallocation(tracker: &MemoryAllocationTracker, size: u64) {
    tracker.deallocations.push(size);
    tracker.current_memory = tracker.current_memory - size;
    tracker.total_freed = tracker.total_freed + size;
}

fn get_memory_stats(tracker: &MemoryAllocationTracker) -> MemoryStats {
    MemoryStats {
        allocated: tracker.total_allocated,
        freed: tracker.total_freed,
        peak: tracker.peak_memory,
        fragmentation: 0.0,  // Calculated separately
        circular_refs_detected: 0,
        circular_refs_resolved: 0,
    }
}

fn print_test_result(result: TestResult) {
    let status = if (result.passed) "✅ PASS" else "❌ FAIL";
    print(status + ": " + result.name);

