// ============================================================================
// Generational Garbage Collector - Core Implementation
// Week 1, Part 1: Generational GC Architecture
// 600 lines
// ============================================================================

// ============================================================================
// Section 1: Core Data Structures (100 lines)
// ============================================================================

enum GCGeneration {
    Young,      // Eden + Survivor
    Old,        // Long-lived objects
}

enum ObjectStatus {
    White,      // Unreachable candidate
    Gray,       // Reachable, children TBD
    Black,      // Fully reachable
}

struct GCObject {
    id: u64,
    size: u64,
    generation: GCGeneration,
    status: ObjectStatus,
    age: u32,           // Number of GC cycles survived
    references: vector, // [obj_id, obj_id, ...]
}

struct GCHeap {
    next_obj_id: u64,
    young_objects: vector,  // [GCObject, ...]
    old_objects: vector,
    young_memory: u64,
    old_memory: u64,
    total_allocated: u64,
    total_collected: u64,
    promotion_threshold: u32,  // Age threshold for promotion
    gc_cycles: u64,
}

struct GCStats {
    total_objects: u32,
    young_count: u32,
    old_count: u32,
    young_memory: u64,
    old_memory: u64,
    white_count: u32,
    gray_count: u32,
    black_count: u32,
    last_collection_time: u64,
    total_collected: u64,
}

// ============================================================================
// Section 2: Heap Initialization & Object Management (80 lines)
// ============================================================================

fn create_gc_heap() -> GCHeap {
    GCHeap {
        next_obj_id: 1,
        young_objects: [],
        old_objects: [],
        young_memory: 0,
        old_memory: 0,
        total_allocated: 0,
        total_collected: 0,
        promotion_threshold: 2,  // Promote after 2 GC cycles
        gc_cycles: 0,
    }
}

fn allocate_object(heap: &GCHeap, size: u64) -> GCObject {
    let obj = GCObject {
        id: heap.next_obj_id,
        size: size,
        generation: GCGeneration.Young,  // All new objects in Young generation
        status: ObjectStatus.White,
        age: 0,
        references: [],
    };

    heap.next_obj_id = heap.next_obj_id + 1;
    heap.total_allocated = heap.total_allocated + size;
    heap.young_memory = heap.young_memory + size;

    obj
}

fn add_object_to_heap(heap: &GCHeap, obj: GCObject) {
    if (obj.generation == GCGeneration.Young) {
        heap.young_objects.push(obj);
    } else {
        heap.old_objects.push(obj);
    };
}

fn set_object_reference(from_obj: &GCObject, to_obj_id: u64) {
    from_obj.references.push(to_obj_id);
}

// ============================================================================
// Section 3: Generational Statistics (70 lines)
// ============================================================================

fn get_gc_stats(heap: &GCHeap) -> GCStats {
    let white = 0;
    let gray = 0;
    let black = 0;

    // Count status in Young generation
    let i = 0;
    while (i < heap.young_objects.len()) {
        let obj = heap.young_objects[i];
        if (obj.status == ObjectStatus.White) {
