    } else if (color == TricolorStatus.Gray) {
        "Gray (Reachable)"
    } else {
        "Black (Processed)"
    }
}

// ============================================================================
// Section 2: Graph-Based Object Tracking (80 lines)
// ============================================================================

struct ObjectGraph {
