    root_set: vector,  // [obj_id, ...]
    gray_queue: vector,  // Queue of Gray objects to process
}

fn create_object_graph() -> ObjectGraph {
    ObjectGraph {
        objects: [],
        root_set: [],
        gray_queue: [],
    }
}

fn add_object_to_graph(graph: &ObjectGraph, obj: TricolorObject) {
    graph.objects.push(obj);
}

fn add_root(graph: &ObjectGraph, obj_id: u64) {
    graph.root_set.push(obj_id);
}

fn find_object(graph: &ObjectGraph, obj_id: u64) -> Option<TricolorObject> {
    let i = 0;
    while (i < graph.objects.len()) {
        let obj = graph.objects[i];
        if (obj.id == obj_id) {
