        if (gray_obj != None) {
            let obj = gray_obj;

            // Process children (mark them gray if white)
            let n = 0;
            while (n < obj.children.len()) {
                let child_id = obj.children[n];

                // Find child object
                let p = 0;
                while (p < graph.objects.len()) {
                    let child = graph.objects[p];
                    if (child.id == child_id && child.color == TricolorStatus.White) {
                        // Newly discovered
                        child.color = TricolorStatus.Gray;
                        graph.gray_queue.push(child_id);
                    };
                    p = p + 1;
                };

                n = n + 1;
            };

            // Mark current object black (fully processed)
            obj.color = TricolorStatus.Black;
        };
    };

