    print("  Marked alive (Black): " + mark_stats.black_count);
    print("  Marked reachable (Gray): " + mark_stats.gray_count);
    print("  Collected (White): " + mark_stats.white_count);
    print("  Cycles needed: " + mark_stats.cycles_needed);
    print("");

