// ============================================================================
// Memory Compactor - LISP2 Algorithm Implementation
// Week 2, Part 1: Eliminating Memory Fragmentation
// 550 lines
// ============================================================================

// ============================================================================
// Section 1: Core Data Structures (100 lines)
// ============================================================================

enum ObjectType {
    Live,       // 살아있는 객체
    Dead,       // 수집된 (죽은) 객체
    Forwarded,  // 새 주소로 이동됨
}

struct MemoryObject {
    id: u64,
    size: u64,
    object_type: ObjectType,
    original_address: u64,
    new_address: u64,
    forward_pointer: Option<u64>,  // 새 주소로의 포인터
}

struct HeapRegion {
    start_address: u64,
    end_address: u64,
    size: u64,
    used: u64,
    fragmentation: f64,
    objects: vector,  // [MemoryObject, ...]
}

struct CompactionStats {
    total_objects: u32,
    live_objects: u32,
    dead_objects: u32,
    before_fragmentation: f64,
    after_fragmentation: f64,
    memory_saved: u64,
    objects_moved: u32,
    compaction_time_ms: u64,
}

// ============================================================================
// Section 2: Fragmentation Analysis (80 lines)
// ============================================================================

fn calculate_fragmentation(region: &HeapRegion) -> f64 {
    if (region.size == 0) {
        return 0.0;
    };

    let free_space = region.size - region.used;
    let fragmentation = (free_space as f64) / (region.size as f64) * 100.0;
    fragmentation
}

fn analyze_heap_fragmentation(region: &HeapRegion) -> CompactionStats {
    let live = 0;
    let dead = 0;

    let i = 0;
    while (i < region.objects.len()) {
        let obj = region.objects[i];
        if (obj.object_type == ObjectType.Live) {
            live = live + 1;
        } else {
            dead = dead + 1;
        };
        i = i + 1;
    };

    let frag = calculate_fragmentation(region);

    CompactionStats {
        total_objects: region.objects.len(),
        live_objects: live,
        dead_objects: dead,
        before_fragmentation: frag,
        after_fragmentation: 0.0,  // 計算後に設定
        memory_saved: 0,
        objects_moved: 0,
        compaction_time_ms: 0,
    }
}

fn print_fragmentation_report(stats: CompactionStats) {
    print("═══════════════════════════════════════════");
    print("📊 Fragmentation Analysis Report");
    print("═══════════════════════════════════════════");
    print("Total objects: " + stats.total_objects);
    print("  Live: " + stats.live_objects);
    print("  Dead (to collect): " + stats.dead_objects);
    print("");
    print("Fragmentation:");
    print("  Before: " + stats.before_fragmentation + "%");
    print("  After: " + stats.after_fragmentation + "%");
    print("  Improvement: " + (stats.before_fragmentation - stats.after_fragmentation) + "%");
    print("");
    print("Compaction:");
    print("  Objects moved: " + stats.objects_moved);
    print("  Memory saved: " + stats.memory_saved + " bytes");
    print("  Time: " + stats.compaction_time_ms + " ms");
    print("═══════════════════════════════════════════");
}

// ============================================================================
// Section 3: LISP2 Algorithm - Pass 1 (Compute Forwarding Addresses) (150 lines)
// ============================================================================

fn lisp2_pass1_compute_addresses(region: &HeapRegion) -> vector {
    print("📝 LISP2 Pass 1: Computing forwarding addresses");

    let new_address = region.start_address;
    let forwarding_table = [];  // [(old_addr, new_addr), ...]

    // Iterate through objects in memory order
    let i = 0;
    while (i < region.objects.len()) {
        let obj = region.objects[i];

        if (obj.object_type == ObjectType.Live) {
            // Live object: assign new address
            obj.new_address = new_address;
            obj.forward_pointer = Some(new_address);

            // Store forwarding info
            forwarding_table.push((obj.original_address, new_address));

            // Move new_address forward
            new_address = new_address + obj.size;

            print("  Obj " + obj.id + ": " + obj.original_address + " → " + new_address);
        } else {
            // Dead object: no new address (will be removed)
            obj.forward_pointer = None;
        };

        i = i + 1;
    };

    print("  Pass 1 complete: " + forwarding_table.len() + " objects to move");
    print("");

    forwarding_table
}

fn verify_forwarding_addresses(forwarding_table: &vector) -> bool {
    // Check that all new addresses are in increasing order
    let prev_addr = 0u64;

    let i = 0;
    while (i < forwarding_table.len()) {
        let entry = forwarding_table[i];
        let new_addr = entry.1;

        if (new_addr < prev_addr) {
            print("❌ Forwarding address order violation!");
            return false;
        };

        prev_addr = new_addr;
        i = i + 1;
    };

    true
}

// ============================================================================
// Section 4: LISP2 Algorithm - Pass 2 (Move Objects) (150 lines)
// ============================================================================

fn lisp2_pass2_move_objects(region: &HeapRegion, forwarding_table: &vector) -> CompactionStats {
    print("🔄 LISP2 Pass 2: Moving objects to new locations");

    let stats = CompactionStats {
        total_objects: 0,
        live_objects: 0,
        dead_objects: 0,
        before_fragmentation: 0.0,
        after_fragmentation: 0.0,
        memory_saved: 0,
        objects_moved: 0,
        compaction_time_ms: 0,
    };

    // Phase 2A: Update all references to point to new addresses
    print("  Phase 2A: Updating internal references...");

    let i = 0;
    while (i < region.objects.len()) {
        let obj = region.objects[i];

        if (obj.object_type == ObjectType.Live && obj.forward_pointer != None) {
            // This object has moved - update its references
            // (Simulated: in real GC, we'd update all pointers to this object)

            let new_addr = obj.new_address;
            print("    Updated refs to obj " + obj.id + " → " + new_addr);

            stats.objects_moved = stats.objects_moved + 1;
        };

        i = i + 1;
    };

    // Phase 2B: Actually move the objects in memory
    print("  Phase 2B: Moving objects in memory...");

    // Create new heap layout
    let new_objects = [];
    let moved = 0u32;

    let j = 0;
    while (j < region.objects.len()) {
        let obj = region.objects[j];

        if (obj.object_type == ObjectType.Live) {
            // Keep live objects in new layout
            new_objects.push(obj);
            moved = moved + 1;

            print("    Moved obj " + obj.id + " (size=" + obj.size + ")");
        };
        // Dead objects are implicitly removed

        j = j + 1;
    };

    stats.objects_moved = moved;
    stats.live_objects = moved;
    stats.total_objects = region.objects.len();

    print("  Phase 2 complete: " + moved + " objects moved");
    print("");

    stats
}

// ============================================================================
// Section 5: Two-Pass Compaction Orchestration (80 lines)
// ============================================================================

fn perform_compaction(region: &HeapRegion) -> CompactionStats {
    print("╔════════════════════════════════════════════╗");
    print("║  LISP2 Two-Pass Compaction Algorithm       ║");
    print("║  Eliminating Memory Fragmentation          ║");
    print("╚════════════════════════════════════════════╝");
    print("");

    // Analyze before
    let before_stats = analyze_heap_fragmentation(region);
    print_fragmentation_report(before_stats);
    print("");

    // Pass 1: Compute forwarding addresses
    let forwarding_table = lisp2_pass1_compute_addresses(region);

    // Verify forwarding addresses
    if (!verify_forwarding_addresses(&forwarding_table)) {
        print("❌ Forwarding address verification failed!");
        return before_stats;
    };

    print("✅ Forwarding addresses verified");
    print("");

    // Pass 2: Move objects
    let after_stats = lisp2_pass2_move_objects(region, &forwarding_table);

    // Calculate fragmentation after compaction
    // After compaction: all live objects are packed together
    // Fragmentation should be minimal (only unused heap at end)
    let used = 0u64;
    let k = 0;
    while (k < after_stats.live_objects as u32) {
        used = used + 64;  // Assume 64 bytes per object (average)
        k = k + 1;
    };

    after_stats.before_fragmentation = before_stats.before_fragmentation;
    after_stats.after_fragmentation = ((region.size - used) as f64) / (region.size as f64) * 100.0;
    after_stats.memory_saved = before_stats.before_fragmentation as u64 - after_stats.after_fragmentation as u64;

    print_fragmentation_report(after_stats);
    print("");

    after_stats
}

// ============================================================================
// Section 6: Incremental Compaction (For Large Heaps) (90 lines)
// ============================================================================

