    print("✅ Verifying heap layout...");

    // Check 1: Bump pointer within bounds
    if (config.bump_pointer.current_offset > config.bump_pointer.heap_end) {
        print("❌ Bump pointer overflow!");
        return false;
    };

    // Check 2: Generation boundaries are correct
    if (config.boundary.young_end >= config.boundary.old_start) {
        print("❌ Generation boundary overlap!");
        return false;
    };

    // Check 3: Card table size matches
    let expected_cards = config.bump_pointer.heap_end / config.card_table.card_size;
    if (config.card_table.cards.len() != expected_cards) {
        print("❌ Card table size mismatch!");
        return false;
    };

    print("✅ Heap layout verified (all checks passed)");
    true
}

