    // Fragmentation = 1280 / 2048 = 62.5% (increased due to smaller used)
    // But relative fragmentation within used space = 0%

    before_frag > 0.0
}

fn test_lisp2_forwarding_address_order() -> bool {
    // Test: Forwarding addresses must be in increasing order

    let region = HeapRegion {
        start_address: 0,
        end_address: 1024,
        size: 1024,
        used: 768,
        fragmentation: 0.0,
        objects: [],
    };

    // 3 live objects with gaps
    region.objects.push(MemoryObject { id: 1, size: 200, object_type: ObjectType.Live, original_address: 0, new_address: 0, forward_pointer: None });
    region.objects.push(MemoryObject { id: 2, size: 100, object_type: ObjectType.Dead, original_address: 200, new_address: 0, forward_pointer: None });
    region.objects.push(MemoryObject { id: 3, size: 300, object_type: ObjectType.Live, original_address: 300, new_address: 0, forward_pointer: None });
    region.objects.push(MemoryObject { id: 4, size: 150, object_type: ObjectType.Dead, original_address: 600, new_address: 0, forward_pointer: None });
    region.objects.push(MemoryObject { id: 5, size: 250, object_type: ObjectType.Live, original_address: 750, new_address: 0, forward_pointer: None });

    let forwarding_table = lisp2_pass1_compute_addresses(&region);
    let verified = verify_forwarding_addresses(&forwarding_table);

    verified
}

fn test_lisp2_no_object_loss() -> bool {
    // Test: All live objects accounted for in compaction

    let region = HeapRegion {
        start_address: 0,
        end_address: 2048,
        size: 2048,
        used: 1280,
        fragmentation: 0.0,
        objects: [],
    };

    let live_count = 0;
    let i = 0;
    while (i < 10) {
        let is_live = (i % 3 == 0);  // ~3 live per 10
        region.objects.push(MemoryObject {
            id: i as u64 + 1,
            size: 128,
            object_type: if (is_live) { ObjectType.Live } else { ObjectType.Dead },
            original_address: (i as u64) * 128,
            new_address: 0,
            forward_pointer: None,
        });

        if (is_live) { live_count = live_count + 1; };
        i = i + 1;
    };

    let forwarding_table = lisp2_pass1_compute_addresses(&region);

    // Forwarding table should contain exactly live_count entries
    forwarding_table.len() as u32 == live_count
}

