fn test_card_marking_write_barrier() -> bool {
    // Test: Write barrier correctly marks cards dirty

    let table = create_card_table(4096);

    // Record Old→Young reference
    write_barrier(&table, 2048, 256);

    // Card containing old_obj (2048) should be dirty
    let card_index = 2048 / table.card_size;
    if (card_index < table.cards.len()) {
        let card = table.cards[card_index];
        card.status == CardStatus.Dirty
    } else {
        false
    }
}

fn test_card_marking_multiple_refs() -> bool {
    // Test: Multiple Old→Young refs in same card

    let table = create_card_table(4096);

    // Multiple references in same card (e.g., 2048-2560 range)
    write_barrier(&table, 2048, 256);
    write_barrier(&table, 2300, 512);
    write_barrier(&table, 2400, 768);

    let card_index = 2048 / table.card_size;
    if (card_index < table.cards.len()) {
        let card = table.cards[card_index];
        // Should have 3 references recorded
        card.references.len() == 3
    } else {
        false
    }
}

fn test_card_marking_clean_cards() -> bool {
    // Test: Cards start clean and become dirty only on write

    let table = create_card_table(2048);

    // Before any writes, all cards should be clean
    let i = 0;
    let all_clean = true;
    while (i < table.cards.len()) {
        let card = table.cards[i];
        if (card.status != CardStatus.Clean) {
            all_clean = false;
        };
        i = i + 1;
    };

    all_clean
}

fn test_card_table_dirty_scan() -> bool {
    // Test: Scanning dirty cards finds Old→Young references

    let table = create_card_table(4096);

    // Write some barriers
    write_barrier(&table, 1024, 256);
    write_barrier(&table, 2048, 512);
    write_barrier(&table, 3000, 768);

    // Scan dirty cards
    let refs_found = scan_dirty_cards(&table);

    // Should find 3 Old→Young references
    refs_found == 3
}

